@PostMapping("/downloadCostRegisterExcelTpl")
@ApiOperation("下载收支登记导入模板")
public void downloadCostRegisterExcelTpl(HttpServletResponse res) {

    InputStream inputStream = null;
    try {
        String fileName = "收支登记批量导入模板.xls";
        // 读取ClassPathResource路径
        String path = FilenameUtils.concat(ConfirmationConstants.RESOURCE_TPL, "CostRegisterBatchImportTpl.xls");
        ClassPathResource classPathResource = new ClassPathResource(path);
        // 设置响应头
        res.setContentType("application/x-octet-stream; charset=UTF-8");
        res.setHeader("Content-Disposition", "attachment;filename=" + URLEncoder.encode(fileName, "UTF-8"));
        res.setHeader("Access-Control-Allow-Origin", "*");

        // 读取Excel的工作簿
        inputStream = classPathResource.getInputStream();
        // 将输入流的内容写入响应输出流
        byte[] buffer = new byte[1024];
        int bytesRead;
        while ((bytesRead = inputStream.read(buffer)) != -1) {
            res.getOutputStream().write(buffer, 0, bytesRead);
        }
        res.flushBuffer();
    } catch (Exception e) {
        log.error("下载失败，原因：{}", e.getMessage(), e);
        throw new BusinessException(AnomalyMsgConstants.HZ.H_400092);
    } finally {
        IOUtils.close(inputStream);
    }
}

@Override
public void downloadSfInvoicedExcel(String projectIds, String deptIds, HttpServletResponse res) {

    ServletOutputStream sos = null;
    Workbook workbook = null;
    try {
        // 读取ClassPathResource路径
        String sfInvoicePath = FilenameUtils.concat(ConfirmationConstants.RESOURCE_TPL, "SFInvoiceBatchApplyTpl.xls");
        String noneInvoicePath = FilenameUtils.concat(ConfirmationConstants.RESOURCE_TPL, "noneInvoiceApplyTpl.xls");

        // 1、获取导出数据
        Map<String, List<HzSFInvoicedExcelDataVo>> map = this.querySfInvoicedExcelData(projectIds, deptIds);
        if (CollUtil.isEmpty(map)) {
            // 如果未获取到数据，那么直接返回!
            throw new BusinessException(AnomalyMsgConstants.HZ.H_400113);
        }
        List<HzSFInvoicedExcelDataVo> ordinaryTicketList = new ArrayList<>();
        List<HzSFInvoicedExcelDataVo> specialTicketList = new ArrayList<>();
        if (null != map.get("ordinaryTicketPara") && null != map.get("specialTicketPara")) {
            ordinaryTicketList = map.get("ordinaryTicketPara");
            specialTicketList = map.get("specialTicketPara");
        }

        long time = DateUtil.date().getTime();
        // 2、一个项目多个导出文件， 变成压缩包后导出，如果只有单个文件， 那么走分支，只导出excel
        if (CollectionUtils.isNotEmpty(ordinaryTicketList) && CollectionUtils.isNotEmpty(specialTicketList)) {
            // 压缩导出
            String zipName =  "未开票申请单" + time + ".zip";
            String tempFolder = "unbilled" + time;
            String tempFilePath = fileLocationConfig.confirmationCenter(tempFolder);
            File tempDirectory = new File(tempFilePath);
            if (!tempDirectory.exists()) {
                tempDirectory.mkdir();
            }

            // 先生成指定的excel文件
            if(CollUtil.isNotEmpty(ordinaryTicketList)){
                Map<String, Object> ordinaryTicketPara = Maps.newHashMap();
                ordinaryTicketPara.put("detailDatas", ordinaryTicketList);
                //模板路径
                ClassPathResource classPathResource = new ClassPathResource(noneInvoicePath);
                TemplateExportParams params = new TemplateExportParams(classPathResource.getPath(), true);
                workbook = ExcelExportUtil.exportExcel(params, ordinaryTicketPara);
                //真实导出路径
                String tempXLSExcel = FilenameUtils.concat(tempFilePath, "未开票申请单"+ ".xls");
                // 指定导出路径
                try (FileOutputStream fos = new FileOutputStream(tempXLSExcel)) {
                    // 先生成excel
                    workbook.write(fos);
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            if(CollUtil.isNotEmpty(specialTicketList)){
                Map<String, Object> specialTicketPara = Maps.newHashMap();
                specialTicketPara.put("detailDatas", specialTicketList);
                //模板路径
                ClassPathResource classPathResource = new ClassPathResource(sfInvoicePath);
                TemplateExportParams params = new TemplateExportParams(classPathResource.getPath(), true);
                workbook = ExcelExportUtil.exportExcel(params, specialTicketPara);
                //真实导出路径
                String tempXLSExcel = FilenameUtils.concat(tempFilePath, "SF专用发票未开票申请单"+ ".xls");
                try (FileOutputStream fos = new FileOutputStream(tempXLSExcel)) {
                    // 先生成excel
                    workbook.write(fos);
                } catch (IOException e) {
                    log.error("写入excel文件失败", e);
                }
