            // 将excel所在的文件加压缩成压缩包
            String zipPath = fileLocationConfig.confirmationCenter(zipName);
            ZipUtil.zip(tempFilePath, zipPath);
            cn.com.bdo.confirmation.utils.FileUtil.safeDel(tempFilePath);
            fileService.downloadByUrl(zipPath);
            cn.com.bdo.confirmation.utils.FileUtil.safeDel(zipPath);
