public class AES256Util {

    private static final Logger LOGGER = LoggerFactory.getLogger(AES256Util.class);

    public static final String CIPHER_ALGORITHM = "AES/CBC/PKCS5Padding";

    public static final   String CHAR_SET = "UTF-8";

    public static byte[] ivBytes = { 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
            0x00, 0x00, 0x00 };

    /**
     * AES加密字符串
     *
     * @param byteContent
     *            需要被加密的字节数组
     * @param key
     *            加密需要的密码
     * @return 密文
     */
    public static byte[] encrypt(byte[] byteContent, String key) {
        try {
            // 先用base64解密
            AlgorithmParameterSpec ivSpec = new IvParameterSpec(ivBytes);
            SecretKeySpec newKey = new SecretKeySpec(key.getBytes(CHAR_SET), "AES");
            Cipher cipher = Cipher.getInstance(CIPHER_ALGORITHM);
            cipher.init(Cipher.ENCRYPT_MODE, newKey, ivSpec);
            return cipher.doFinal(byteContent);
        } catch (Exception ex) {
            LOGGER.error("清单图片解码错误：", ex);
            return null;
        }
    }

    /**
     * 解密AES加密过的字符串
     *
     * @param content
     *            AES加密过过的内容
     * @param key
     *            加密时的密码
     * @return 明文
     */
    public static byte [] decrypt(byte [] content, String key) {
        try {
            // 先用base64解密
            AlgorithmParameterSpec ivSpec = new IvParameterSpec(ivBytes);
            SecretKeySpec newKey = new SecretKeySpec(key.getBytes(CHAR_SET), "AES");
            Cipher cipher = Cipher.getInstance(CIPHER_ALGORITHM);
            cipher.init(Cipher.DECRYPT_MODE, newKey, ivSpec);
            return cipher.doFinal(content);
        } catch (Exception ex) {
            LOGGER.error("解码错误：", ex);
            return null;
        }
    }


    /**
     * 进行aes解密返回base64图片格式
     * @param resourceStr
     * @param key
     * @return
     */
    public static byte[] decryptBase64(String resourceStr, String key) {
        try {
            // 先用base64解密
            byte[] byteContent = Base64.decode(resourceStr);
            AlgorithmParameterSpec ivSpec = new IvParameterSpec(ivBytes);
            SecretKeySpec newKey = new SecretKeySpec(key.getBytes(CHAR_SET), "AES");
            Cipher cipher = Cipher.getInstance(CIPHER_ALGORITHM);
            cipher.init(Cipher.DECRYPT_MODE, newKey, ivSpec);
            byte[] resultByte = cipher.doFinal(byteContent);
            // String result = new String(resultByte, CHAR_SET);
            return  resultByte;
        } catch (Exception ex) {
            LOGGER.error("清单图片解码错误：", ex);
            return null;
        }
    }

    /**
     *
     * @param filePath
     * @return
     */
    public static String fileEncryptToBase64Str(String filePath, String key){
        AlgorithmParameterSpec ivSpec = new IvParameterSpec(ivBytes);
        FileInputStream in = null;
        try {
            in = new FileInputStream(filePath);
            SecretKeySpec newKey = new SecretKeySpec(key.getBytes(CHAR_SET), "AES");
            Cipher cipher = Cipher.getInstance(CIPHER_ALGORITHM);
            cipher.init(Cipher.ENCRYPT_MODE, newKey, ivSpec);
            byte[] buffer = new byte[in.available()];
            in.read(buffer);
            return Base64.encode(cipher.doFinal(buffer));
        } catch (Exception e) {
            e.printStackTrace();
        }
        return null;
    }

    /**
     * 文件加密
     * @param key 加密key
     * @param srcFile 加密源文件
     * @param destPath 加密输出地址
     * @param fileName 加密输出文件名
     * @return
     */
    public static String fileEncrypt(String key, String srcFile, String destPath, String fileName){
        AlgorithmParameterSpec ivSpec = new IvParameterSpec(ivBytes);
        InputStream in = null;
        FileOutputStream out = null;
        try {
            SecretKeySpec newKey = new SecretKeySpec(key.getBytes(CHAR_SET), "AES");
            Cipher cipher = Cipher.getInstance(CIPHER_ALGORITHM);
            cipher.init(Cipher.ENCRYPT_MODE, newKey, ivSpec);
            in = new FileInputStream(srcFile);
            out = new FileOutputStream(destPath + File.separator + fileName);
            byte[] buffer = new byte[in.available()];
            in.read(buffer);
            out.write(cipher.doFinal(buffer));
